+export function normalizeErrorStackOptions(
+  input: unknown
+): NormalizedErrorStackOptions | undefined {
+  if (typeof input !== 'object' || input === null || Array.isArray(input)) {
+    return undefined;
+  }
+  const value = input as ErrorStackOptions;
+  const mode: ErrorStackMode =
+    value.mode === 'string' || value.mode === 'frames' || value.mode === 'off'
+      ? value.mode
+      : 'off';
+  if (
+    value.maxStackLines !== undefined &&
+    (!Number.isInteger(value.maxStackLines) || value.maxStackLines <= 0)
+  ) {
+    return { ...defaults(), mode: 'off' };
+  }
+  const includeCauses: IncludeCauses =
+    value.includeCauses === 'direct' || value.includeCauses === 'deep'
+      ? value.includeCauses
+      : 'none';
+  const validCauseDepth =
+    value.maxCauseDepth === undefined || Number.isInteger(value.maxCauseDepth);
+  const classFilter = Array.isArray(value.classFilter)
+    ? value.classFilter.filter((name): name is string => typeof name === 'string')
+    : typeof value.classFilter === 'string'
+      ? [value.classFilter]
+      : undefined;
+  return {
+    mode,
+    normalizeNewlines: value.normalizeNewlines === true,
+    trimLeadingWhitespace: value.trimLeadingWhitespace !== false,
+    maxStackLines: value.maxStackLines,
+    stripInternalFrames:
