+const preparedErrors = new WeakSet<Error>();
+
+function matchesErrorClass(error: Error, superJson: SuperJSON): boolean {
+  const filter = superJson.errorStackOptions?.classFilter;
+  return !filter || filter.length === 0 || filter.includes(error.name);
+}
+
+function prepareError(error: Error, superJson: SuperJSON, depth: number, seen: Set<Error>): Error {
+  if (preparedErrors.has(error)) return error;
+  const options = superJson.errorStackOptions!;
+  const clone = new Error(
+    options.sanitizeMessage && matchesErrorClass(error, superJson)
+      ? sanitizeMessage(error.message)
+      : error.message
+  );
+  clone.name = error.name;
+  clone.stack = error.stack;
+  preparedErrors.add(clone);
+  if (options.includeCauses !== 'none' && depth > 0 && error.cause instanceof Error && !seen.has(error.cause)) {
+    (clone as any).cause = prepareError(error.cause, superJson, depth - 1, new Set([...seen, error]));
+  }
+  if (error.name === 'AggregateError' && 'errors' in (error as any)) {
+    (clone as any).errors = (error as any).errors;
+  }
+  return clone;
+}
+
+function serializeError(error: Error, superJson: SuperJSON): any {
+  const options = superJson.errorStackOptions;
+  const configured = options !== undefined;
+  const source = configured && !preparedErrors.has(error)
+    ? prepareError(error, superJson, options.includeCauses === 'direct' ? 1 : options.maxCauseDepth, new Set())
+    : error;
+  const baseError: any = { name: source.name, message: source.message };
+  if ((configured ? options.includeCauses !== 'none' : 'cause' in source) && 'cause' in source) {
+    baseError.cause = (source as any).cause;
+  }
+  if (source.name === 'AggregateError' && 'errors' in (source as any)) baseError.errors = (source as any).errors;
+  superJson.allowedErrorProps.forEach(prop => {
+    if (configured && options.mode === 'off' && prop === 'stack') return;
+    if (configured && prop === 'stackFrames') return;
+    baseError[prop] = (source as any)[prop];
+  });
+  if (configured && options.mode === 'string' && matchesErrorClass(source, superJson) && superJson.allowedErrorProps.includes('stack') && typeof source.stack === 'string') {
+    baseError.stack = processStackString(source.stack, options);
